import java.io.*;import java.util.*;class Main{static Map<String,List<String>>pref;static ArrayList<List<String>>ans;static int len;static void dfs(ArrayList<String>sq){int d=sq.size();if(d==len){ans.add(new ArrayList<>(sq));return;}StringBuilder p=new StringBuilder();for(String row:sq)p.append(row.charAt(d));for(String w:pref.getOrDefault(p.toString(),Collections.emptyList())){sq.add(w);dfs(sq);sq.remove(sq.size()-1);}}static List<List<String>> solve(String[]words){ans=new ArrayList<>();if(words.length==0)return ans;len=words[0].length();pref=new HashMap<>();for(String w:words)for(int i=0;i<=len;i++)pref.computeIfAbsent(w.substring(0,i),k->new ArrayList<>()).add(w);for(String w:words){ArrayList<String>sq=new ArrayList<>();sq.add(w);dfs(sq);}return ans;}static String fmt(List<List<String>>a){StringBuilder out=new StringBuilder("[");for(int i=0;i<a.size();i++){if(i>0)out.append(',');out.append('[');for(int j=0;j<a.get(i).size();j++){if(j>0)out.append(',');out.append('"').append(a.get(i).get(j)).append('"');}out.append(']');}return out.append(']').toString();}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);String[]w=new String[n];for(int i=0;i<n;i++)w[i]=d[idx++];if(tc>0)out.append("\n\n");out.append(fmt(solve(w)));}System.out.print(out);}}
